const body = $input.first().json.body || {};

const isSlashCommand = !!body.command;

// Mensagem direta: o texto está em body.text ou body.event.text
const perguntaBruta = (
  body.text ||
  body.event?.text ||
  ''
).trim();

const pergunta = perguntaBruta
  .replace(/<@[A-Z0-9]+>/g, '')
  .trim();

if (!pergunta) {
  throw new Error('Nenhuma pergunta encontrada na mensagem.');
}

// Canal e usuário para resposta
const channelId   = body.channel_id   || body.event?.channel || body.channel || '';
const userId      = body.user_id       || body.event?.user    || '';
const responseUrl = body.response_url  || '';

console.log(`Pergunta recebida: "${pergunta}" | Canal: ${channelId} | Usuário: ${userId}`);

return [{
  json: {
    pergunta,
    channelId,
    userId,
    responseUrl,
    isSlashCommand,
    timestamp: new Date().toISOString()
  }
}];

const todosArtigos = $input.all().map(i => i.json);

// Pega a pergunta do nó de extração 
const contexto = $('Extrai pergunta do slack').first().json;
const pergunta = contexto.pergunta;

// Filtra últimos 7 dias
const seteDiasAtras = new Date();
seteDiasAtras.setDate(seteDiasAtras.getDate() - 7);

const artigosFiltrados = todosArtigos
  .filter(a => {
    if (!a.data_coleta) return false;
    const dataArtigo = new Date(a.data_coleta);
    return dataArtigo >= seteDiasAtras;
  })
  .filter(a => {
    // Aceita artigos com score >= 6 ou sem score definido
    const score = Number(a.pontuacao_relevancia);
    return isNaN(score) || score >= 6;
  })
  .sort((a, b) => (Number(b.pontuacao_relevancia) || 0) - (Number(a.pontuacao_relevancia) || 0))
  .slice(0, 30);

console.log(`Total de artigos na base: ${todosArtigos.length}`);
console.log(`Artigos filtrados (7 dias, score>=6): ${artigosFiltrados.length}`);

// Formata os artigos de forma compacta para o contexto da IA
const contextoArtigos = artigosFiltrados.length > 0
  ? artigosFiltrados.map((a, i) =>
      `[${i+1}] ${a.titulo || 'Sem título'}\n` +
      `Fonte: ${a.fonte || '?'} | Score: ${a.pontuacao_relevancia || '?'}/10 | ` +
      `Categoria: ${a.categoria || '?'} | Sentimento: ${a.sentimento || '?'}\n` +
      `Resumo: ${a.resumo || 'Sem resumo'}\n` +
      `URL: ${a.url || ''}\n` +
      (a.oportunidade_startup ? `Startup: ${a.oportunidade_startup}\n` : '')
    ).join('\n---\n')
  : 'Nenhum artigo coletado nos últimos 7 dias. O Workflow 1 ainda não foi executado ou não encontrou artigos.';

return [{
  json: {
    pergunta,
    channelId:     contexto.channelId,
    userId:        contexto.userId,
    responseUrl:   contexto.responseUrl,
    contextoArtigos,
    totalArtigos:  artigosFiltrados.length
  }
}];

