const j = $input.first().json;

// Extrai o texto da IA (mesmo padrão dos outros workflows)
const respostaIA = (
  j?.content?.[0]?.text ||
  j?.message?.content ||
  j?.choices?.[0]?.message?.content ||
  j?.text ||
  ''
).trim();

if (!respostaIA) {
  throw new Error('A IA retornou uma resposta vazia.');
}

// Recupera o contexto (canal, usuário, total de artigos)
const ctx = $('Filtra e prepara para a IA').first().json;

// Monta a mensagem final formatada para o Slack
const mensagem = [
  `🤖 *Inteli AI Intelligence Hub*`,
  ``,
  respostaIA,
  ``,
  `---`,
  `_Base: ${ctx.totalArtigos} artigos coletados nos últimos 7 dias_`
].join('\n');

console.log(`Resposta montada. Tamanho: ${mensagem.length} chars. Enviando para canal: ${ctx.channelId}`);

return [{
  json: {
    mensagem,
    channelId:    ctx.channelId,
    userId:       ctx.userId,
    totalArtigos: ctx.totalArtigos
  }
}];
